import React from 'react';
import { FormElement, ElementType } from '../types';

export interface ElementDefinition {
    type: ElementType;
    // Component for the final form
    renderer: React.ComponentType<{
        element: FormElement;
        register: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        errors: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        watch?: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        setValue?: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        control?: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        prefix?: string;
        config?: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        allCustomFunctions?: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        completeValues?: any; // eslint-disable-line @typescript-eslint/no-explicit-any
        renderRecursiveElement?: (element: FormElement, parentIndex?: number, prefixForName?: string, parentDirection?: string) => React.ReactNode;
    }>;
    // Component for the builder canvas preview
    canvas: React.ComponentType<{
        element: FormElement;
        isSelected: boolean;
    }>;
    // Component for the properties sidebar
    properties: React.ComponentType<{
        element: FormElement;
        onChange: (key: keyof FormElement, value: any) => void;
    }>;
    // Logic to generate Zod schema (optional)
    getSchema?: (element: FormElement) => any;
}

const registry: Partial<Record<ElementType, ElementDefinition>> = {};

export const registerElement = (definition: ElementDefinition) => {
    registry[definition.type] = definition;
};

export const getElement = (type: ElementType): ElementDefinition | undefined => {
    return registry[type];
};

export const getRegisteredTypes = (): ElementType[] => {
    return Object.keys(registry) as ElementType[];
};
