import React from 'react';

export interface CheckboxOption {
    label: string;
    value: string;
    description?: string;
}

interface CheckboxGroupProps {
    label?: string;
    error?: string;
    description?: string;
    options: CheckboxOption[];
    value?: string[];
    onValueChange?: (value: string[]) => void;
    required?: boolean;
    disabled?: boolean;
    name: string;
    direction?: 'vertical' | 'horizontal';
    view?: 'default' | 'blocks' | 'tabs';
}

const CheckboxTabOption = ({ option, name, isChecked, isFirst, isLast, disabled, onChange }: any) => {
    const [isFocused, setIsFocused] = React.useState(false);

    return (
        <label
            className={`
                flex-1 relative inline-flex items-center justify-center py-2 px-4 text-sm font-medium border cursor-pointer focus:z-10
                ${isFirst ? 'rounded-l-md' : ''}
                ${isLast ? 'rounded-r-md' : ''}
                ${isChecked
                    ? 'bg-primary text-primary-foreground border-primary z-10'
                    : 'bg-white text-slate-700 border-slate-300 hover:bg-slate-50'
                }
                ${isFocused ? 'ring-2 ring-primary ring-offset-2 z-20' : ''}
                ${!isFirst ? '-ml-px' : ''}
                ${disabled ? 'opacity-60 cursor-not-allowed' : ''}
            `}
        >
            <input
                type="checkbox"
                id={`${name}-${option.value}`}
                checked={isChecked}
                onChange={(e) => onChange(option.value, e.target.checked)}
                disabled={disabled}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
                className="sr-only"
            />
            {option.label}
        </label>
    );
};

const CheckboxBlockOption = ({ option, name, isChecked, disabled, onChange }: any) => {
    const [isFocused, setIsFocused] = React.useState(false);
    return (
        <label
            className={`
                flex items-start gap-4 p-3 rounded-lg border cursor-pointer transition-all
                ${isChecked ? 'border-primary bg-slate-50' : 'border-slate-200 hover:border-slate-300 bg-white'}
                ${isFocused ? 'ring-2 ring-primary border-primary' : ''}
                ${disabled ? 'opacity-60 cursor-not-allowed' : ''}
            `}
        >
            <div className="flex items-center h-5 mt-0.5">
                <input
                    type="checkbox"
                    id={`${name}-${option.value}`}
                    checked={isChecked}
                    onChange={(e) => onChange(option.value, e.target.checked)}
                    disabled={disabled}
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => setIsFocused(false)}
                    className="h-4 w-4 rounded border-slate-300 text-primary accent-primary focus:ring-primary"
                />
            </div>
            <div className="flex flex-col">
                <span className={`text-sm font-medium ${isChecked ? 'text-slate-900' : 'text-slate-900'}`}>{option.label}</span>
                {option.description && (
                    <span className="text-xs text-slate-500 mt-0.5">{option.description}</span>
                )}
            </div>
        </label>
    );
};

export const CheckboxGroup: React.FC<CheckboxGroupProps> = ({
    label,
    error,
    description,
    options,
    value = [],
    onValueChange,
    required,
    disabled,
    name,
    direction = 'vertical',
    view = 'default'
}) => {
    const handleChange = (optionValue: string, checked: boolean) => {
        if (!onValueChange) return;

        if (checked) {
            onValueChange([...value, optionValue]);
        } else {
            onValueChange(value.filter((v) => v !== optionValue));
        }
    };

    const isBlocks = view === 'blocks';
    const isTabs = view === 'tabs';

    if (isTabs) {
        return (
            <div className="w-full">
                <div className="flex rounded-md shadow-sm isolate">
                    {options.map((option, index) => (
                        <CheckboxTabOption
                            key={option.value}
                            option={option}
                            name={name}
                            isChecked={value.includes(option.value)}
                            isFirst={index === 0}
                            isLast={index === options.length - 1}
                            disabled={disabled}
                            onChange={handleChange}
                        />
                    ))}
                </div>
                {description && !error && <p className="text-xs text-slate-500 mt-2">{description}</p>}
                {error && <p className="text-xs text-red-500 mt-2">{error}</p>}
            </div>
        );
    }

    return (
        <div className="w-full">
            <div className={`
                ${isBlocks ? 'grid gap-3 grid-cols-1' : ''}
                ${(!isBlocks && !isTabs) && direction === 'vertical' ? 'flex flex-col gap-3' : ''}
                ${(!isBlocks && !isTabs) && direction === 'horizontal' ? 'flex flex-row flex-wrap gap-3' : ''}
            `}>
                {options.map((option) => {
                    const isChecked = value.includes(option.value);

                    if (isBlocks) {
                        return (
                            <CheckboxBlockOption
                                key={option.value}
                                option={option}
                                name={name}
                                isChecked={isChecked}
                                disabled={disabled}
                                onChange={handleChange}
                            />
                        );
                    }

                    // Default rendering
                    return (
                        <div key={option.value} className="flex items-start gap-2">
                            <input
                                type="checkbox"
                                id={`${name}-${option.value}`}
                                checked={isChecked}
                                onChange={(e) => handleChange(option.value, e.target.checked)}
                                disabled={disabled}
                                className="mt-1 h-4 w-4 rounded border-slate-300 text-primary accent-primary focus:ring-2 focus:ring-primary disabled:cursor-not-allowed disabled:opacity-50"
                            />
                            <label
                                htmlFor={`${name}-${option.value}`}
                                className="text-sm text-slate-700 cursor-pointer select-none leading-tight pt-0.5"
                            >
                                {option.label}
                                {option.description && (
                                    <span className="block text-xs text-slate-400 mt-0.5">{option.description}</span>
                                )}
                            </label>
                        </div>
                    );
                })}
            </div>
            {description && !error && (
                <p className="text-xs text-slate-500 mt-2">{description}</p>
            )}
            {error && (
                <p className="text-xs text-red-500 mt-2">{error}</p>
            )}
        </div>
    );
};
CheckboxGroup.displayName = "CheckboxGroup";
