import React from 'react';
import { FormElement } from '../../types';
import { Slider } from '../../../ui/fields/Slider';
import { RangeSlider } from '../../../ui/fields/RangeSlider';
import { useFormContext } from 'react-hook-form';

interface SlidersRendererProps {
    element: FormElement;
    prefix?: string;
}

export const SlidersRenderer: React.FC<SlidersRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    const min = element.min || element.sliderMin || 0;
    const max = element.max || element.sliderMax || 100;
    const step = element.step || element.sliderStep || 1;

    if (element.type === 'range-slider') {
        return (
            <RangeSlider
                key={element.id}
                name={fieldName}
                label={element.label}
                description={element.description}
                error={error}
                min={min}
                max={max}
                step={step}
                sliderFormatPrefix={element.sliderFormatPrefix}
                sliderFormatSuffix={element.sliderFormatSuffix}
                value={value}
                onValueChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
            />
        );
    }

    return (
        <Slider
            key={element.id}
            name={fieldName}
            label={element.label}
            description={element.description}
            error={error}
            min={min}
            max={max}
            step={step}
            value={value}
            orientation={element.type === 'vertical-slider' ? 'vertical' : 'horizontal'}
            onValueChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
        />
    );
};
