import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';

interface TextPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const TextProperties: React.FC<TextPropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />
            {/* Common sections will be handled in the main PropertiesPanel for now to avoid massive duplication */}
        </div>
    );
};
