import React from 'react';
import { FormElement } from '../../types';
import { Switch } from '../../../ui/fields/Switch';
import { useFormContext } from 'react-hook-form';

interface ToggleRendererProps {
    element: FormElement;
    prefix?: string;
}

export const ToggleRenderer: React.FC<ToggleRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    return (
        <Switch
            key={element.id}
            error={error}
            label={element.toggleText || 'Ativar'}
            checked={value || false}
            onCheckedChange={(checked) => setValue(fieldName, checked, { shouldValidate: true })}
        />
    );
};
