import React from 'react';
import { FormElement } from '../../types';
import { Calendar, Clock } from 'lucide-react';

interface DateTimeCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const DateTimeCanvas: React.FC<DateTimeCanvasProps> = ({ element, isSelected }) => {
    return (
        <div className={`w-full h-10 rounded-md border bg-white px-3 text-sm flex items-center justify-between ${isSelected ? 'border-primary' : 'border-slate-300'}`}>
            <span className="text-slate-400">
                {element.placeholder || (element.type === 'time' ? '--:--' : 'Select date...')}
            </span>
            {element.type === 'time' ? (
                <Clock size={16} className="text-slate-400" />
            ) : (
                <Calendar size={16} className="text-slate-400" />
            )}
        </div>
    );
};
