import React, { useState, useRef, useEffect } from 'react';
import { Calendar as CalendarIcon, ChevronLeft, ChevronRight, X } from 'lucide-react';
import {
    format,
    addMonths,
    subMonths,
    startOfMonth,
    endOfMonth,
    startOfWeek,
    endOfWeek,
    eachDayOfInterval,
    isSameMonth,
    isSameDay,
    isToday,
    parseISO,
    isValid,
    isAfter,
    isBefore,
    parse,
    setMonth,
    setYear,
    getYear,
    getMonth
} from 'date-fns';

interface DatePickerProps {
    label?: string;
    error?: string;
    description?: string;
    value?: string | string[];
    onChange?: (value: string | string[]) => void;
    required?: boolean;
    disabled?: boolean;
    name?: string;
    placeholder?: string;
    mode?: 'single' | 'multiple' | 'range';
    minDate?: string;
    maxDate?: string;
    dateFormatDisplay?: string;
}

export const DatePicker: React.FC<DatePickerProps> = ({
    label,
    error,
    description,
    value,
    onChange,
    required,
    disabled,
    placeholder = "Select date",
    mode = 'single',
    dateFormatDisplay = "dd/MM/yyyy"
}) => {
    const [isOpen, setIsOpen] = useState(false);
    const [viewDate, setViewDate] = useState(new Date());
    const [inputValue, setInputValue] = useState('');
    const [isFocused, setIsFocused] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    // Initialize viewDate and inputValue based on value
    useEffect(() => {
        const displayVal = getDisplayValue();
        setInputValue(displayVal);

        if (isOpen) {
            let initialDate = new Date();
            if (value) {
                if (typeof value === 'string' && isValid(parseISO(value))) {
                    initialDate = parseISO(value);
                } else if (Array.isArray(value) && value.length > 0 && isValid(parseISO(value[value.length - 1]))) {
                    initialDate = parseISO(value[value.length - 1]);
                }
            }
            setViewDate(initialDate);
        }
    }, [isOpen, value]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleDayClick = (day: Date) => {
        const dateStr = format(day, 'yyyy-MM-dd');

        if (mode === 'single') {
            onChange?.(dateStr);
            setIsOpen(false);
        } else if (mode === 'multiple') {
            const currentVal = Array.isArray(value) ? value : [];
            const exists = currentVal.includes(dateStr);
            let newVal;
            if (exists) {
                newVal = currentVal.filter(d => d !== dateStr);
            } else {
                newVal = [...currentVal, dateStr];
            }
            onChange?.(newVal);
        } else if (mode === 'range') {
            const currentVal = Array.isArray(value) ? value : [];
            // If empty or full range (2 items), start new select
            if (currentVal.length === 0 || currentVal.length === 2) {
                onChange?.([dateStr]);
            } else if (currentVal.length === 1) {
                const start = parseISO(currentVal[0]);
                if (isBefore(day, start)) {
                    onChange?.([dateStr, currentVal[0]]);
                } else {
                    onChange?.([currentVal[0], dateStr]);
                }
                // Don't close immediately on range selection? User might want to adjust?
                // Standard behavior is usually close after second pick.
                setIsOpen(false);
            }
        }
    };

    const getDisplayValue = () => {
        if (!value || (Array.isArray(value) && value.length === 0)) return '';

        const formatDateFn = (dateStr: string) => {
            const date = parseISO(dateStr);
            return isValid(date) ? format(date, dateFormatDisplay) : dateStr;
        };

        if (mode === 'single' && typeof value === 'string') {
            return formatDateFn(value);
        }

        if (mode === 'multiple' && Array.isArray(value)) {
            return value.map(d => formatDateFn(d)).join(', ');
        }

        if (mode === 'range' && Array.isArray(value)) {
            if (value.length === 1) return `${formatDateFn(value[0])} a ...`;
            if (value.length === 2) return `${formatDateFn(value[0])} a ${formatDateFn(value[1])}`;
        }

        return String(value);
    };

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = e.target.value;
        setInputValue(val);

        if (mode === 'single') {
            const parsedDate = parse(val, dateFormatDisplay, new Date());
            if (isValid(parsedDate)) {
                const dateStr = format(parsedDate, 'yyyy-MM-dd');
                if (dateStr !== value) {
                    onChange?.(dateStr);
                    setViewDate(parsedDate);
                }
            }
        }
    };

    const handleInputBlur = () => {
        // If empty, clear value
        if (!inputValue && value) {
            onChange?.(mode === 'single' ? '' : []);
            return;
        }

        // Revert to valid display value if current input is invalid (only for single mode)
        if (mode === 'single') {
            const parsedDate = parse(inputValue, dateFormatDisplay, new Date());
            if (!isValid(parsedDate)) {
                setInputValue(getDisplayValue());
            }
        }
    };

    const isSelected = (day: Date) => {
        const dateStr = format(day, 'yyyy-MM-dd');

        if (mode === 'single') {
            return value === dateStr;
        }

        if (mode === 'multiple' && Array.isArray(value)) {
            return value.includes(dateStr);
        }

        if (mode === 'range' && Array.isArray(value)) {
            if (value.length === 0) return false;
            if (value.includes(dateStr)) return true; // Endpoints

            if (value.length === 2) {
                const start = parseISO(value[0]);
                const end = parseISO(value[1]);
                return isAfter(day, start) && isBefore(day, end);
            }
        }

        return false;
    };

    const getDayClass = (day: Date) => {
        const dateStr = format(day, 'yyyy-MM-dd');
        let classes = "w-8 h-8 flex items-center justify-center text-sm rounded-full transition-colors ";

        const isSel = isSelected(day);
        const isCurrentMonth = isSameMonth(day, viewDate);

        if (!isCurrentMonth) {
            classes += "text-slate-300 ";
        } else {
            classes += "text-slate-700 hover:bg-slate-100 ";
        }

        if (mode === 'range' && Array.isArray(value) && value.length === 2) {
            const start = parseISO(value[0]);
            const end = parseISO(value[1]);
            const isStart = isSameDay(day, start);
            const isEnd = isSameDay(day, end);
            const isBetween = isAfter(day, start) && isBefore(day, end);

            if (isStart || isEnd) {
                return classes + "bg-primary text-primary-foreground hover:opacity-90";
            }
            if (isBetween) {
                return classes + "bg-primary/10 text-primary rounded-none"; // Square for between
            }
        } else {
            if (isSel) {
                return classes + "bg-primary text-primary-foreground hover:opacity-90";
            }
        }

        if (isToday(day) && !isSel) {
            return classes + "border border-primary text-primary";
        }

        return classes;
    };

    const days = eachDayOfInterval({
        start: startOfWeek(startOfMonth(viewDate)),
        end: endOfWeek(endOfMonth(viewDate))
    });

    return (
        <div className="w-full" ref={containerRef}>
            <div className="relative">
                <input
                    ref={inputRef}
                    type="text"
                    value={inputValue}
                    onChange={handleInputChange}
                    onFocus={() => setIsFocused(true)}
                    onBlur={(e) => {
                        handleInputBlur();
                        setIsFocused(false);
                    }}
                    onClick={() => !disabled && setIsOpen(true)}
                    placeholder={placeholder}
                    className={`
                        w-full rounded-md border bg-white px-3 py-2 text-sm shadow-sm 
                        focus:outline-none transition-all
                        ${error ? 'border-red-500' : isFocused ? 'border-primary ring-1 ring-primary' : 'border-slate-300'}
                        ${disabled ? 'opacity-60 cursor-not-allowed bg-slate-50' : ''}
                    `}
                />
                <div className="absolute inset-y-0 right-3 flex items-center pointer-events-none text-slate-400">
                    <CalendarIcon size={16} />
                </div>

                {isOpen && !disabled && (
                    <div className="absolute top-full left-0 mt-1 p-3 bg-white border border-slate-200 rounded-lg shadow-xl z-50 w-64">
                        <div className="flex items-center justify-between mb-4 gap-1">
                            <button
                                type="button"
                                onClick={() => setViewDate(subMonths(viewDate, 1))}
                                className="p-1 hover:bg-slate-100 rounded text-slate-500 shrink-0"
                            >
                                <ChevronLeft size={16} />
                            </button>

                            <div className="flex items-center gap-1 flex-1 min-w-0">
                                <select
                                    className="text-sm font-medium text-slate-900 bg-transparent border-none p-0 focus:ring-0 cursor-pointer hover:text-primary outline-none flex-1 truncate"
                                    value={getMonth(viewDate)}
                                    onChange={(e) => setViewDate(setMonth(viewDate, parseInt(e.target.value)))}
                                >
                                    {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map((m, i) => (
                                        <option key={i} value={i}>{m}</option>
                                    ))}
                                </select>
                                <select
                                    className="text-sm font-medium text-slate-900 bg-transparent border-none p-0 focus:ring-0 cursor-pointer hover:text-primary outline-none"
                                    value={getYear(viewDate)}
                                    onChange={(e) => setViewDate(setYear(viewDate, parseInt(e.target.value)))}
                                >
                                    {Array.from({ length: 121 }, (_, i) => new Date().getFullYear() - 110 + i).reverse().map(y => (
                                        <option key={y} value={y}>{y}</option>
                                    ))}
                                </select>
                            </div>

                            <button
                                type="button"
                                onClick={() => setViewDate(addMonths(viewDate, 1))}
                                className="p-1 hover:bg-slate-100 rounded text-slate-500 shrink-0"
                            >
                                <ChevronRight size={16} />
                            </button>
                        </div>

                        <div className="grid grid-cols-7 gap-1 mb-2 text-center">
                            {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(d => (
                                <div key={d} className="text-xs font-medium text-slate-400">
                                    {d}
                                </div>
                            ))}
                        </div>

                        <div className="grid grid-cols-7 gap-1">
                            {days.map((day, i) => (
                                <button
                                    key={i}
                                    type="button"
                                    onClick={() => handleDayClick(day)}
                                    className={getDayClass(day)}
                                >
                                    {format(day, 'd')}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {description && !error && <p className="text-xs text-slate-500 mt-1">{description}</p>}
            {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
        </div>
    );
};
