import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { Switch } from '../../../ui/fields/Switch';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';

interface PhonePropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const PhoneProperties: React.FC<PhonePropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />
            <AccordionItem title="Phone options" defaultOpen>
                <div className="space-y-4 pt-2">
                    <div className="flex items-center justify-between">
                        <label className="text-xs text-slate-700">Unmask value</label>
                        <Switch
                            checked={element.unmaskValue || false}
                            onCheckedChange={(c) => onChange('unmaskValue', c)}
                        />
                    </div>
                </div>
            </AccordionItem>
        </div>
    );
};
