import React from 'react';
import { FormElement } from '../../types';

interface ButtonRendererProps {
    element: FormElement;
}

export const ButtonRenderer: React.FC<ButtonRendererProps> = ({ element }) => {
    let variantClass = "bg-primary text-white hover:bg-primary/90";
    if (element.type === 'reset-button' || element.type === 'secondary-button') variantClass = "bg-slate-100 text-slate-700 hover:bg-slate-200";
    if (element.type === 'danger-button') variantClass = "bg-red-500 text-white hover:bg-red-600";

    const isSubmit = element.type === 'submit-button' || element.type === 'primary-button' || element.type === 'button';

    return (
        <button
            key={element.id}
            type={isSubmit ? 'submit' : 'button'}
            className={`w-full px-4 py-2 rounded-md text-sm font-medium transition-colors shadow-sm ${variantClass}`}
        >
            {element.label || 'Button'}
        </button>
    );
};
