import React from 'react';
import { FormElement } from '../../types';
import { DatePicker } from '../../../ui/fields/DatePicker';
import { Input } from '../../../ui/wireframe-ports/Input';
import { useFormContext } from 'react-hook-form';

interface DateTimeRendererProps {
    element: FormElement;
    prefix?: string;
}

export const DateTimeRenderer: React.FC<DateTimeRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { watch, setValue, register, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    if (element.type === 'time') {
        // Use wireframe Input for time as it was before
        return (
            <Input
                key={element.id}
                type="time"
                error={error}
                label={element.label}
                placeholder={element.placeholder}
                {...(element.name ? register(fieldName) : {})}
            />
        );
    }

    let dateMode: 'single' | 'multiple' | 'range' = 'single';
    if (element.type === 'multiple-dates') dateMode = 'multiple';
    if (element.type === 'date-range') dateMode = 'range';

    return (
        <DatePicker
            key={element.id}
            name={fieldName}
            label={element.label}
            description={element.description}
            placeholder={element.placeholder}
            error={error}
            required={element.required}
            value={value}
            mode={dateMode}
            dateFormatDisplay={element.dateFormatDisplay}
            onChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
        />
    );
};
