import React from 'react';
import { FormElement } from '../../types';
import { Input } from '../../../ui/fields/Input';

interface TextRendererProps {
    element: FormElement;
    register: any;
    errors: any;
    prefix?: string;
    config?: any;
}

export const TextRenderer: React.FC<TextRendererProps> = ({
    element,
    register,
    errors,
    prefix = '',
    config
}) => {
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;

    // Global layout overrides
    const globalSize = config?.layout?.size || 'md';
    const globalFloat = config?.layout?.floatPlaceholders ? 'on' : 'default';

    const commonProps = {
        error,
        required: element.required, // Logic for required is handled in FormRenderer for now
        disabled: element.disabled || element.readOnly,
        placeholder: element.placeholder,
        prefix: element.prefix,
        suffix: element.suffix,
        mask: element.mask,
        size: element.size || globalSize,
        autoFloat: element.autoFloat || globalFloat,
        min: element.min ?? element.minValue,
        max: element.max ?? element.maxValue,
    };

    const {
        autoFloat,
        ...safeProps
    } = commonProps as any;

    return (
        <Input
            key={element.id}
            type={element.type as any}
            {...safeProps}
            {...(element.name ? register(fieldName) : {})}
        />
    );
};
