import React from 'react';

export interface RadioOption {
    label: string;
    value: string;
    description?: string;
}

interface RadioGroupProps {
    label?: string;
    error?: string;
    description?: string;
    options: RadioOption[];
    value?: string;
    onValueChange?: (value: string) => void;
    required?: boolean;
    disabled?: boolean;
    name: string;
    view?: 'default' | 'blocks' | 'tabs';
    direction?: 'vertical' | 'horizontal';
}

const RadioTabOption = ({ option, name, isSelected, isFirst, isLast, disabled, onValueChange }: any) => {
    const [isFocused, setIsFocused] = React.useState(false);
    const roundedInfo = `
        ${isFirst ? 'rounded-l-md' : ''} 
        ${isLast ? 'rounded-r-md' : ''}
    `;

    return (
        <label
            className={`
                flex-1 relative inline-flex items-center justify-center py-2 px-4 text-sm font-medium border cursor-pointer focus:z-10
                ${roundedInfo}
                ${isSelected
                    ? 'bg-primary text-primary-foreground border-primary z-10'
                    : 'bg-white text-slate-700 border-slate-300 hover:bg-slate-50'
                }
                ${isFocused ? 'ring-2 ring-primary ring-offset-2 z-20' : ''}
                ${!isFirst ? '-ml-px' : ''}
                ${disabled ? 'opacity-60 cursor-not-allowed' : ''}
            `}
        >
            <input
                type="radio"
                name={name}
                value={option.value}
                checked={isSelected}
                onChange={(e) => onValueChange?.(e.target.value)}
                disabled={disabled}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
                className="sr-only" // Hide native radio
            />
            {option.label}
        </label>
    );
};

const RadioBlockOption = ({ option, name, isSelected, disabled, onValueChange }: any) => {
    const [isFocused, setIsFocused] = React.useState(false);
    return (
        <label
            className={`
                flex items-start gap-4 p-3 rounded-lg border cursor-pointer transition-all
                ${isSelected ? 'border-primary bg-slate-50' : 'border-slate-200 hover:border-slate-300 bg-white'}
                ${isFocused ? 'ring-2 ring-primary border-primary' : ''}
                ${disabled ? 'opacity-60 cursor-not-allowed' : ''}
            `}
        >
            <div className="flex items-center h-5 mt-0.5">
                <input
                    type="radio"
                    name={name}
                    value={option.value}
                    checked={isSelected}
                    onChange={(e) => onValueChange?.(e.target.value)}
                    disabled={disabled}
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => setIsFocused(false)}
                    className="h-4 w-4 border-slate-300 text-primary accent-primary focus:ring-primary"
                />
            </div>
            <div className="flex flex-col">
                <span className={`text-sm font-medium ${isSelected ? 'text-slate-900' : 'text-slate-900'}`}>{option.label}</span>
                {option.description && (
                    <span className="text-xs text-slate-500 mt-0.5">{option.description}</span>
                )}
            </div>
        </label>
    );
};

export const RadioGroup: React.FC<RadioGroupProps> = ({
    label,
    error,
    description,
    options,
    value,
    onValueChange,
    required,
    disabled,
    name,
    view = 'default',
    direction = 'vertical'
}) => {

    // Logic for Tabs View
    if (view === 'tabs') {
        return (
            <div className="flex rounded-md shadow-sm">
                {options.map((option, index) => (
                    <RadioTabOption
                        key={option.value}
                        option={option}
                        name={name}
                        isSelected={value === option.value}
                        isFirst={index === 0}
                        isLast={index === options.length - 1}
                        disabled={disabled}
                        onValueChange={onValueChange}
                    />
                ))}
            </div>
        );
    }

    // Logic for Blocks View
    if (view === 'blocks') {
        return (
            <div className="grid gap-3 grid-cols-1">
                {options.map((option) => (
                    <RadioBlockOption
                        key={option.value}
                        option={option}
                        name={name}
                        isSelected={value === option.value}
                        disabled={disabled}
                        onValueChange={onValueChange}
                    />
                ))}
            </div>
        );
    }

    // Default View
    return (
        <div className={`flex gap-3 ${direction === 'vertical' ? 'flex-col' : 'flex-row flex-wrap'}`}>
            {options.map((option) => (
                <div key={option.value} className="flex items-center gap-2">
                    <input
                        type="radio"
                        id={`${name}-${option.value}`}
                        name={name}
                        value={option.value}
                        checked={value === option.value}
                        onChange={(e) => onValueChange?.(e.target.value)}
                        disabled={disabled}
                        className="h-4 w-4 border-slate-300 text-primary accent-primary focus:ring-2 focus:ring-primary disabled:cursor-not-allowed disabled:opacity-50"
                    />
                    <label
                        htmlFor={`${name}-${option.value}`}
                        className="text-sm text-slate-700 cursor-pointer select-none leading-tight pt-0.5"
                    >
                        {option.label}
                        {option.description && (
                            <span className="block text-xs text-slate-400 mt-0.5">{option.description}</span>
                        )}
                    </label>
                </div>
            ))}
        </div>
    );
};
RadioGroup.displayName = "RadioGroup";
