import React from 'react';
import { FormElement } from '../../types';
import { RichTextEditor } from '../../../ui/fields/RichTextEditor';
import { useFormContext } from 'react-hook-form';

interface AdvancedRendererProps {
    element: FormElement;
    prefix?: string;
    config?: any;
}

export const AdvancedRenderer: React.FC<AdvancedRendererProps> = ({
    element,
    prefix = '',
    config
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    switch (element.type) {
        case 'wysiwyg':
            return (
                <RichTextEditor
                    key={element.id}
                    name={fieldName}
                    value={value}
                    placeholder={element.placeholder}
                    disabled={element.disabled || element.readOnly}
                    error={error}
                    onChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
                />
            );

        case 'signature':
            return (
                <div className="w-full">
                    <div
                        className="border border-slate-300 rounded-md bg-slate-50 flex items-center justify-center text-slate-400 border-dashed"
                        style={{ height: element.canvasHeight || 160 }}
                    >
                        Signature Canvas (Coming Soon)
                    </div>
                    {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
                </div>
            );

        case 'captcha':
            return (
                <div className="bg-slate-50 border border-slate-200 rounded p-4 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-5 h-5 border-2 border-slate-300 rounded" />
                        <span className="text-sm font-medium text-slate-700">I'm not a robot</span>
                    </div>
                    <img src="https://www.gstatic.com/recaptcha/api2/logo_48.png" alt="reCAPTCHA" className="w-8 h-8 opacity-50" />
                </div>
            );

        default:
            return null;
    }
};
