import React from 'react';
import { FormElement } from '../../types';
import { evaluateFormExpression } from '../../core/expressions';
import { useFormContext } from 'react-hook-form';

interface StaticRendererProps {
    element: FormElement;
    completeValues?: Record<string, any>; // eslint-disable-line @typescript-eslint/no-explicit-any
    allCustomFunctions?: Record<string, Function>;
}

export const StaticRenderer: React.FC<StaticRendererProps> = ({
    element,
    completeValues,
    allCustomFunctions
}) => {
    const getContent = () => {
        if (element.useExpressionValue && element.expression) {
            return evaluateFormExpression(element.expression, completeValues || {}, allCustomFunctions || {});
        }
        return element.content || '';
    };

    const content = getContent();

    switch (element.type) {
        case 'h1':
            return <h1 key={element.id} className="text-3xl font-bold text-slate-900">{content || 'Heading 1'}</h1>;
        case 'h2':
            return <h2 key={element.id} className="text-2xl font-bold text-slate-900">{content || 'Heading 2'}</h2>;
        case 'h3':
            return <h3 key={element.id} className="text-xl font-bold text-slate-900">{content || 'Heading 3'}</h3>;
        case 'h4':
            return <h4 key={element.id} className="text-lg font-bold text-slate-900">{content || 'Heading 4'}</h4>;
        case 'p':
            return <p key={element.id} className="text-sm text-slate-600 leading-relaxed">{content || 'Paragraph text...'}</p>;
        case 'quote':
            return <blockquote key={element.id} className="border-l-4 border-slate-300 pl-4 italic text-slate-600">{content || 'Quote...'}</blockquote>;
        case 'divider':
            return <hr key={element.id} className="border-slate-200" />;
        case 'link':
            return (
                <a
                    key={element.id}
                    href={element.href || '#'}
                    target={element.target || '_blank'}
                    className="text-primary hover:underline"
                >
                    {content || 'Link text'}
                </a>
            );
        case 'image':
            const imgSrc = element.src || content;
            const borderRadiusMap = { none: '0', sm: '0.25rem', md: '0.5rem', lg: '1rem', full: '9999px' };
            const borderRadius = borderRadiusMap[element.borderRadius as keyof typeof borderRadiusMap] || '0.375rem';

            return (
                <div key={element.id} className={`w-full flex ${element.align === 'center' ? 'justify-center' : element.align === 'right' ? 'justify-end' : 'justify-start'}`}>
                    {imgSrc ? (
                        <img
                            src={imgSrc}
                            alt={element.alt || 'Image'}
                            className="max-w-full shadow-sm"
                            style={{
                                width: element.width ? (isNaN(Number(element.width)) ? element.width : `${element.width}px`) : '100%',
                                height: element.height ? (isNaN(Number(element.height)) ? element.height : `${element.height}px`) : 'auto',
                                objectFit: element.objectFit || 'cover',
                                borderRadius: borderRadius,
                                aspectRatio: element.aspectRatio && element.aspectRatio !== 'auto' ? element.aspectRatio.replace('/', ' / ') : undefined
                            }}
                        />
                    ) : (
                        <div className="w-full h-32 bg-slate-100 rounded-md flex flex-col items-center justify-center text-slate-400 border border-slate-200">
                            <span>Image Placeholder</span>
                        </div>
                    )}
                </div>
            );
        case 'static-html':
            return <div key={element.id} dangerouslySetInnerHTML={{ __html: element.html || '' }} />;
        default:
            return null;
    }
};
