import React from 'react';
import { FormElement } from '../../types';
import { SmartFieldRenderer } from '../../renderer/SmartFieldRenderer';
import { useFormContext } from 'react-hook-form';

interface SelectRendererProps {
    element: FormElement;
    prefix?: string;
}

export const SelectRenderer: React.FC<SelectRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    return (
        <SmartFieldRenderer
            key={element.id}
            element={element}
            value={value}
            onChange={(val: any) => setValue(fieldName, val, { shouldValidate: true })}
            error={error}
            fieldName={fieldName}
        />
    );
};
