import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Trash2, Plus } from 'lucide-react';

interface MatrixPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const MatrixProperties: React.FC<MatrixPropertiesProps> = ({ element, onChange }) => {
    const handleUpdateItem = (listKey: 'matrixRows' | 'matrixColumns', index: number, field: 'text' | 'value', value: string) => {
        const list = [...(element[listKey] || [])];
        list[index] = { ...list[index], [field]: value };
        if (field === 'text' && !list[index].value) {
            list[index].value = value.toLowerCase().replace(/\s+/g, '_');
        }
        onChange(listKey, list);
    };

    const handleAddItem = (listKey: 'matrixRows' | 'matrixColumns') => {
        const list = [...(element[listKey] || []), { text: 'New Item', value: `new_item_${Date.now()}` }];
        onChange(listKey, list);
    };

    const handleRemoveItem = (listKey: 'matrixRows' | 'matrixColumns', index: number) => {
        const list = [...(element[listKey] || [])];
        list.splice(index, 1);
        onChange(listKey, list);
    };

    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} showPlaceholder={false} />

            <AccordionItem title="Rows" defaultOpen>
                <div className="space-y-2 pt-2">
                    {(element.matrixRows || []).map((row, i) => (
                        <div key={i} className="flex gap-2 items-center">
                            <Input
                                value={row.text}
                                onChange={(e) => handleUpdateItem('matrixRows', i, 'text', e.target.value)}
                                className="h-8"
                            />
                            <button onClick={() => handleRemoveItem('matrixRows', i)} className="text-slate-300 hover:text-red-500">
                                <Trash2 size={14} />
                            </button>
                        </div>
                    ))}
                    <button
                        onClick={() => handleAddItem('matrixRows')}
                        className="w-full py-1.5 border border-dashed border-slate-300 rounded text-[10px] uppercase font-bold text-slate-500 hover:border-primary hover:text-primary transition-all flex items-center justify-center gap-1"
                    >
                        <Plus size={12} /> Add Row
                    </button>
                </div>
            </AccordionItem>

            <AccordionItem title="Columns" defaultOpen>
                <div className="space-y-2 pt-2">
                    {(element.matrixColumns || []).map((col: any, i: number) => (
                        <div key={i} className="flex gap-2 items-center">
                            <Input
                                value={col.text}
                                onChange={(e) => handleUpdateItem('matrixColumns', i, 'text', e.target.value)}
                                className="h-8"
                            />
                            <button onClick={() => handleRemoveItem('matrixColumns', i)} className="text-slate-300 hover:text-red-500">
                                <Trash2 size={14} />
                            </button>
                        </div>
                    ))}
                    <button
                        onClick={() => handleAddItem('matrixColumns')}
                        className="w-full py-1.5 border border-dashed border-slate-300 rounded text-[10px] uppercase font-bold text-slate-500 hover:border-primary hover:text-primary transition-all flex items-center justify-center gap-1"
                    >
                        <Plus size={12} /> Add Column
                    </button>
                </div>
            </AccordionItem>
        </div>
    );
};
