import React from 'react';
import { FormElement } from '../../types';

interface ButtonCanvasProps {
    element: FormElement;
}

export const ButtonCanvas: React.FC<ButtonCanvasProps> = ({ element }) => {
    let btnClass = "bg-primary text-white";
    if (element.type === 'reset-button' || element.type === 'secondary-button') btnClass = "bg-slate-100 text-slate-700 border border-slate-200";
    if (element.type === 'danger-button') btnClass = "bg-red-500 text-white";

    return (
        <div className={`w-full px-4 py-2 rounded-md text-sm font-bold text-center shadow-sm select-none ${btnClass}`}>
            {element.label || 'Button'}
        </div>
    );
};
