import React from 'react';
import { FormElement } from '../../types';
import { RadioGroup } from '../../../ui/fields/RadioGroup';
import { useFormContext } from 'react-hook-form';
import { SmartFieldRenderer } from '../../renderer/SmartFieldRenderer';

interface RadioRendererProps {
    element: FormElement;
    prefix?: string;
}

export const RadioRenderer: React.FC<RadioRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    if (element.type === 'radio-group' || element.type === 'radio-blocks' || element.type === 'radio-tabs') {
        return (
            <SmartFieldRenderer
                key={element.id}
                element={element}
                value={value}
                onChange={(val: any) => setValue(fieldName, val, { shouldValidate: true })}
                error={error}
                fieldName={fieldName}
            />
        );
    }

    return (
        <RadioGroup
            key={element.id}
            name={fieldName}
            options={[{ label: element.radioText || 'Radio', value: element.radioValue || '1' }]}
            value={value}
            error={error}
            onValueChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
        />
    );
};
