import React from 'react';
import { FormElement } from '../../types';
import { Input } from '../../../ui/wireframe-ports/Input';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';

interface BasePropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
    showPlaceholder?: boolean;
}

export const BaseProperties: React.FC<BasePropertiesProps> = ({
    element,
    onChange,
    showPlaceholder = true
}) => {
    return (
        <AccordionItem title="Properties" defaultOpen>
            <div className="space-y-4 pt-2">
                <Input
                    label="Name"
                    value={element.name || ''}
                    onChange={(e) => onChange('name', e.target.value)}
                />
                <Input
                    label="Label"
                    value={element.label || ''}
                    onChange={(e) => onChange('label', e.target.value)}
                />
                {showPlaceholder && (
                    <Input
                        label="Placeholder"
                        value={element.placeholder || ''}
                        onChange={(e) => onChange('placeholder', e.target.value)}
                    />
                )}
                <Input
                    label="Tooltip"
                    value={element.tooltip || ''}
                    onChange={(e) => onChange('tooltip', e.target.value)}
                />
            </div>
        </AccordionItem>
    );
};
