import React from 'react';
import { FormElement } from '../../types';

interface MatrixCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const MatrixCanvas: React.FC<MatrixCanvasProps> = ({ element, isSelected }) => {
    const isTable = element.type === 'matrix-table';
    const rows = element.matrixRows || [{ text: 'Row 1', value: 'r1' }, { text: 'Row 2', value: 'r2' }];
    const cols = element.matrixColumns || [{ text: 'Col 1', value: 'c1' }, { text: 'Col 2', value: 'c2' }];

    return (
        <div className={`w-full overflow-hidden rounded border bg-white ${isSelected ? 'border-primary' : 'border-slate-200'}`}>
            <table className="w-full text-[10px] text-left border-collapse">
                <thead>
                    <tr className="bg-slate-50 border-b border-slate-200">
                        <th className="p-1.5 border-r border-slate-200"></th>
                        {cols.map((col: any, i: number) => (
                            <th key={i} className="p-1.5 text-center font-bold text-slate-400 uppercase tracking-tighter border-r border-slate-200 last:border-0">
                                {col.text}
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {rows.map((row: any, i: number) => (
                        <tr key={i} className="border-b border-slate-100 last:border-0">
                            <td className="p-1.5 font-medium text-slate-600 border-r border-slate-200 bg-slate-50/30">
                                {row.text}
                            </td>
                            {cols.map((_: any, j: number) => (
                                <td key={j} className="p-1.5 text-center border-r border-slate-100 last:border-0">
                                    {isTable ? (
                                        <div className="h-5 w-full bg-slate-50 border border-slate-200 rounded" />
                                    ) : (
                                        <div className="h-3 w-3 rounded-full border border-slate-300 bg-white mx-auto" />
                                    )}
                                </td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};
