import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Switch } from '../../../ui/fields/Switch';

interface TextAreaPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const TextAreaProperties: React.FC<TextAreaPropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />
            <div className="space-y-4 pt-4">
                <div className="flex items-center justify-between">
                    <label className="text-xs text-slate-700">Auto grow</label>
                    <Switch
                        checked={element.autoGrow || false}
                        onCheckedChange={(c) => onChange('autoGrow', c)}
                    />
                </div>
                <Input
                    label="Rows"
                    type="number"
                    value={element.rows || ''}
                    onChange={(e) => onChange('rows', parseInt(e.target.value))}
                />
            </div>
        </div>
    );
};
