import React from 'react';
import { FormElement } from '../../types';

interface RadioCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const RadioCanvas: React.FC<RadioCanvasProps> = ({ element, isSelected }) => {
    const isSingle = element.type === 'radio';

    if (!isSingle) {
        if (element.view === 'tabs' || element.type === 'radio-tabs') {
            return (
                <div className="flex w-full rounded-md border border-slate-200 bg-slate-50 p-1">
                    {element.options?.map((opt, i) => (
                        <div key={i} className={`flex-1 py-1.5 text-center text-[10px] font-bold rounded ${i === 0 ? 'bg-white shadow-sm text-slate-900 border border-slate-200' : 'text-slate-400 opacity-60'}`}>
                            {opt.label}
                        </div>
                    ))}
                </div>
            );
        }
        if (element.view === 'blocks' || element.type === 'radio-blocks') {
            return (
                <div className="space-y-2">
                    {element.options?.map((opt, i) => (
                        <div key={i} className={`flex items-center gap-3 p-3 rounded-md border bg-white ${isSelected ? 'border-primary shadow-sm' : 'border-slate-200'}`}>
                            <div className={`h-4 w-4 rounded-full border border-slate-300 shrink-0`}></div>
                            <div className="flex flex-col">
                                <span className="text-sm font-medium text-slate-900 leading-none">{opt.label}</span>
                                {opt.description && <span className="text-[10px] text-slate-500 mt-1">{opt.description}</span>}
                            </div>
                        </div>
                    ))}
                </div>
            );
        }
        return (
            <div className="space-y-2">
                {element.options?.map((opt, i) => (
                    <div key={i} className="flex items-center gap-2">
                        <div className="h-4 w-4 rounded-full border border-slate-300 bg-white shrink-0"></div>
                        <div className="flex flex-col">
                            <span className="text-sm text-slate-700">{opt.label}</span>
                            {opt.description && <span className="text-[10px] text-slate-400">{opt.description}</span>}
                        </div>
                    </div>
                ))}
            </div>
        );
    }

    return (
        <div className={`flex items-center gap-2 ${element.align === 'center' ? 'justify-center' : element.align === 'right' ? 'justify-end' : ''}`}>
            <div className={`h-4 w-4 rounded-full border ${isSelected ? 'border-primary' : 'border-slate-300'} bg-white flex items-center justify-center`}>
                {element.selectedByDefault && <div className="h-2 w-2 rounded-full bg-primary"></div>}
            </div>
            <span className="text-sm text-slate-700">{element.radioText || 'Radio'}</span>
        </div>
    );
};
