'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { WelcomePageConfig, ThemeConfig, FormElement } from '../types';
import { SmartFieldRenderer } from './SmartFieldRenderer';
// Using native button element instead of shadcn Button component

interface WelcomeScreenProps {
    config: WelcomePageConfig;
    onStart: () => void;
    themeConfig?: ThemeConfig;
    renderElement: (element: FormElement) => React.ReactNode;
}

export const WelcomeScreen: React.FC<WelcomeScreenProps> = ({
    config,
    onStart,
    themeConfig,
    renderElement
}) => {
    const {
        title = 'Bem-vindo!',
        description = '',
        buttonText = 'Começar',
        layout = 'centered',
        backgroundType = 'color',
        backgroundColor,
        containerColor,
        backgroundImage,
        coverImage,
        logo,
        elements = []
    } = config;

    // Background styles
    const backgroundStyles: React.CSSProperties = {
        backgroundColor: backgroundColor || 'transparent',
        ...(backgroundType === 'image' && backgroundImage ? {
            backgroundImage: `url(${backgroundImage})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundRepeat: 'no-repeat'
        } : {})
    };

    // Layout classes
    const layoutClasses = {
        centered: 'flex items-center justify-center min-h-screen',
        cover: 'flex flex-col min-h-screen',
        'split-left': 'grid grid-cols-1 md:grid-cols-2 min-h-screen',
        'split-right': 'grid grid-cols-1 md:grid-cols-2 min-h-screen'
    };

    const containerClasses = {
        centered: 'max-w-5xl w-full mx-auto px-6 py-12',
        cover: 'flex-1 flex items-center justify-center px-6 py-12',
        'split-left': 'order-2 md:order-1 flex items-center justify-center px-8 py-12',
        'split-right': 'order-2 flex items-center justify-center px-8 py-12'
    };

    const renderContent = () => (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="w-full"
        >
            {/* Custom Elements - Full fidelity from Canvas */}
            {elements.length > 0 ? (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ delay: 0.2 }}
                    className="w-full"
                >
                    <div className="grid grid-cols-12 gap-x-6 gap-y-8 text-left">
                        {elements.map((element) => renderElement(element))}
                    </div>
                </motion.div>
            ) : (
                <div className="text-center text-slate-400 py-10 border-2 border-dashed border-slate-200 rounded-lg">
                    Adicione elementos na tela de Boas-vindas
                </div>
            )}
        </motion.div>
    );

    // Centered Layout
    if (layout === 'centered') {
        return (
            <div className={layoutClasses.centered} style={backgroundStyles}>
                <div
                    className={containerClasses.centered}
                    style={{
                        backgroundColor: containerColor || 'white',
                        borderRadius: '1rem',
                        boxShadow: containerColor ? '0 20px 25px -5px rgb(0 0 0 / 0.1)' : 'none'
                    }}
                >
                    {renderContent()}
                </div>
            </div>
        );
    }

    // Cover Layout
    if (layout === 'cover') {
        return (
            <div className={layoutClasses.cover} style={backgroundStyles}>
                {coverImage && (
                    <div
                        className="h-64 md:h-96 bg-cover bg-center"
                        style={{ backgroundImage: `url(${coverImage})` }}
                    />
                )}
                <div className={containerClasses.cover}>
                    <div
                        className="max-w-5xl w-full"
                        style={{
                            backgroundColor: containerColor || 'white',
                            padding: '3rem',
                            borderRadius: '1rem',
                            boxShadow: containerColor ? '0 20px 25px -5px rgb(0 0 0 / 0.1)' : 'none'
                        }}
                    >
                        {renderContent()}
                    </div>
                </div>
            </div>
        );
    }

    // Split Layouts
    return (
        <div className={layoutClasses[layout]} style={backgroundStyles}>
            {/* Image Side */}
            <div
                className={`${layout === 'split-left' ? 'order-1 md:order-2' : 'order-1'} bg-cover bg-center min-h-[300px] md:min-h-screen`}
                style={{
                    backgroundImage: coverImage ? `url(${coverImage})` : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
                }}
            />

            {/* Content Side */}
            <div className={containerClasses[layout]}>
                <div className="w-full">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};
