'use client';

import React, { useState } from 'react';
import { FormRenderer } from './FormRenderer';
import { FormElement, ThemeConfig, WelcomePageConfig, ThankYouPageConfig } from '../types';
import { ThemeProvider } from './ThemeProvider';

interface FullPageRendererProps {
    formId: string;
    elements: FormElement[];
    config?: any;
    themeConfig?: ThemeConfig;
    welcomeConfig?: WelcomePageConfig;
    thankYouConfig?: ThankYouPageConfig;
    viewDevice?: any;
    onSubmit: (data: any) => Promise<void>;
}

export function FullPageRenderer({
    elements,
    config,
    themeConfig,
    welcomeConfig,
    thankYouConfig,
    viewDevice,
    onSubmit
}: FullPageRendererProps) {
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (data: any) => {
        setIsSubmitting(true);
        try {
            await onSubmit(data);
        } catch (error) {
            console.error('Submission error:', error);
            throw error;
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <ThemeProvider themeConfig={themeConfig}>
            <div className="min-h-screen w-full" style={{
                backgroundColor: themeConfig?.style?.background?.value || '#f8fafc',
                ...(themeConfig?.style?.background?.type === 'image' ? {
                    backgroundImage: `url(${themeConfig?.style?.background?.value})`,
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    backgroundAttachment: 'fixed'
                } : {})
            }}>
                <FormRenderer
                    elements={elements}
                    onSubmit={handleSubmit}
                    isSubmitting={isSubmitting}
                    config={config}
                    themeConfig={themeConfig}
                    welcomePage={welcomeConfig}
                    thankYouPage={thankYouConfig}
                    viewDevice={viewDevice}
                />
            </div>
        </ThemeProvider>
    );
}
