import React, { useMemo } from 'react';
import { useFetchOptions } from '../../form-engine/hooks/useFetchOptions';
import { BaseSelect, BaseSelectProps } from './BaseSelect';
import { SelectOption } from '@/components/form-engine/types';

interface TopOfMindFieldProps extends Omit<BaseSelectProps, 'options'> {
    options?: SelectOption[];
    allowCustomValue?: boolean;
    // Data Source Props
    dataSourceType?: 'list' | 'json' | 'endpoint';
    dataSourceUrl?: string;
    dataSourceJson?: string;
    dataSourceValueKey?: string;
    dataSourceLabelKey?: string;
    dataSourceDescriptionKey?: string;
    dataSourceDataKey?: string;
    searchParam?: string;
    updateOptionsOnSearch?: boolean;
}

export const TopOfMindField: React.FC<TopOfMindFieldProps> = ({
    options: staticOptions = [],
    value,
    onChange,
    allowCustomValue = false,
    onSearchChange,
    // Data Source Props
    ...props
}) => {
    const { options: internalOptions, loading, refetch } = useFetchOptions({
        ...props,
        options: staticOptions,
        type: 'top-of-mind'
    } as any);

    // Handle Search for Remote
    const handleSearchChange = (query: string) => {
        onSearchChange?.(query);
        if (props.updateOptionsOnSearch) {
            refetch(query);
        }
    };

    // Top of Mind specific: search logic that includes aliases
    // We use internalOptions now
    const searchableOptions = useMemo(() => {
        return internalOptions.map((opt: SelectOption) => {
            // Ensure aliases are searchable
            const aliases = Array.isArray(opt.aliases)
                ? opt.aliases.join(' ')
                : typeof opt.aliases === 'string'
                    ? opt.aliases
                    : '';

            return {
                ...opt,
                searchContent: `${opt.label} ${aliases}`.toLowerCase()
            };
        });
    }, [internalOptions]);

    return (
        <BaseSelect
            {...props}
            options={searchableOptions}
            value={value}
            onChange={(val) => onChange?.(Array.isArray(val) ? val[0] : val)}
            searchable={true}
            multiple={false}
            allowNewOption={allowCustomValue}
            onSearchChange={handleSearchChange}
            trackBy="searchContent"
            minSearchLength={1}
            loading={loading || props.loading}
            noResultsText={allowCustomValue ? "Pressione Enter para usar este valor" : "Nenhuma sugestão encontrada"}
        />
    );
};
