import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Switch } from '../../../ui/fields/Switch';

import { OptionsProperties } from '../common/OptionsProperties';

interface CheckboxPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const CheckboxProperties: React.FC<CheckboxPropertiesProps> = ({ element, onChange }) => {
    const isSingle = element.type === 'checkbox';

    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} showPlaceholder={false} />
            <div className="space-y-4 pt-4">
                {isSingle ? (
                    <>
                        <Input
                            label="Checkbox label"
                            value={element.checkboxLabel || ''}
                            onChange={(e) => onChange('checkboxLabel', e.target.value)}
                        />
                        <div className="flex items-center justify-between">
                            <label className="text-xs text-slate-700">Selected by default</label>
                            <Switch
                                checked={element.selectedByDefault || false}
                                onCheckedChange={(c) => onChange('selectedByDefault', c)}
                            />
                        </div>
                    </>
                ) : (
                    <OptionsProperties element={element} onChange={onChange} />
                )}
            </div>
        </div>
    );
};
