import React from 'react';
import { FormElement } from '../../types';

interface StaticCanvasProps {
    element: FormElement;
}

export const StaticCanvas: React.FC<StaticCanvasProps> = ({ element }) => {
    switch (element.type) {
        case 'h1':
            return <div className="text-xl font-bold text-slate-900 border-b border-slate-100 pb-1">{element.content || 'Heading 1'}</div>;
        case 'h2':
            return <div className="text-lg font-bold text-slate-800">{element.content || 'Heading 2'}</div>;
        case 'h3':
            return <div className="text-base font-bold text-slate-700">{element.content || 'Heading 3'}</div>;
        case 'h4':
            return <div className="text-sm font-bold text-slate-600 uppercase tracking-wider">{element.content || 'Heading 4'}</div>;
        case 'p':
            return <div className="text-xs text-slate-500 line-clamp-2">{element.content || 'Paragraph text...'}</div>;
        case 'quote':
            return <div className="border-l-2 border-slate-200 pl-3 italic text-xs text-slate-400">{element.content || 'Quote...'}</div>;
        case 'divider':
            return <div className="w-full h-px bg-slate-200" />;
        case 'link':
            return <div className="text-xs text-primary underline">{element.content || 'Link text'}</div>;
        case 'image':
            const canvasImgSrc = element.src || element.content;
            const brMap = { none: '0', sm: '0.25rem', md: '0.5rem', lg: '1rem', full: '9999px' };
            const br = brMap[element.borderRadius as keyof typeof brMap] || '0.375rem';

            return (
                <div className={`w-full flex ${element.align === 'center' ? 'justify-center' : element.align === 'right' ? 'justify-end' : 'justify-start'}`}>
                    {canvasImgSrc ? (
                        <img
                            src={canvasImgSrc}
                            alt={element.alt || 'Image'}
                            className="max-w-full shadow-sm border border-slate-100"
                            style={{
                                width: element.width ? (isNaN(Number(element.width)) ? element.width : `${element.width}px`) : '100%',
                                height: element.height ? (isNaN(Number(element.height)) ? element.height : `${element.height}px`) : 'auto',
                                objectFit: element.objectFit || 'cover',
                                borderRadius: br,
                                aspectRatio: element.aspectRatio && element.aspectRatio !== 'auto' ? element.aspectRatio.replace('/', ' / ') : undefined
                            }}
                        />
                    ) : (
                        <div className="w-full h-24 bg-slate-100 rounded flex flex-col items-center justify-center text-slate-300 gap-1 border border-slate-200 border-dashed">
                            <div className="w-8 h-8 rounded border border-slate-200 border-dashed" />
                            <span className="text-[10px] uppercase font-bold tracking-widest">{element.alt || 'No Image'}</span>
                        </div>
                    )}
                </div>
            );
        case 'static-html':
            return (
                <div className="text-[10px] font-mono p-2 bg-slate-900 text-emerald-400 rounded overflow-hidden h-12">
                    {element.html || '<!-- HTML Code -->'}
                </div>
            );
        default:
            return null;
    }
};
