import React from 'react';

interface SliderProps {
    label?: string;
    error?: string;
    description?: string;
    min?: number;
    max?: number;
    step?: number;
    value?: number;
    onValueChange?: (value: number) => void;
    required?: boolean;
    disabled?: boolean;
    name: string;
    orientation?: 'horizontal' | 'vertical';
}

export const Slider: React.FC<SliderProps> = ({
    label,
    error,
    description,
    min = 0,
    max = 100,
    step = 1,
    value,
    onValueChange,
    required,
    disabled,
    name,
    orientation = 'horizontal'
}) => {
    const [localValue, setLocalValue] = React.useState(value || min);

    React.useEffect(() => {
        if (value !== undefined) {
            setLocalValue(value);
        }
    }, [value]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newVal = Number(e.target.value);
        setLocalValue(newVal);
        onValueChange?.(newVal);
    };

    const isVertical = orientation === 'vertical';

    return (
        <div className={`w-full ${isVertical ? 'flex flex-row gap-4 items-center h-48' : ''}`}>
            {!isVertical && (
                <div className="flex justify-end items-center mb-2 w-full">
                    <span className="text-sm font-mono text-slate-500 bg-slate-100 px-2 py-0.5 rounded">
                        {localValue}
                    </span>
                </div>
            )}

            {isVertical && (
                <div className="flex flex-col items-center justify-between h-40 py-1">
                    <span className="text-xs text-slate-400">{max}</span>
                    <span className="text-xs text-slate-400">{min}</span>
                </div>
            )}

            <div className={`relative ${isVertical ? 'h-40 w-8 flex items-center justify-center' : 'w-full'}`}>
                <input
                    type="range"
                    id={name}
                    min={min}
                    max={max}
                    step={step}
                    value={localValue}
                    onChange={handleChange}
                    disabled={disabled}
                    //@ts-ignore - orient is not standard HTML attribute but works in Firefox
                    orient={isVertical ? "vertical" : undefined}
                    style={isVertical ? { writingMode: 'vertical-lr', direction: 'rtl' } : undefined}
                    className={
                        isVertical
                            ? "h-full w-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-primary disabled:opacity-50"
                            : "w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-primary disabled:opacity-50"
                    }
                />
            </div>

            {isVertical && (
                <div className="flex flex-col gap-1">
                    <span className="text-sm font-mono text-slate-500 bg-slate-100 px-2 py-0.5 rounded self-start">
                        {localValue}
                    </span>
                </div>
            )}

            {!isVertical && (
                <div className="flex justify-between mt-1 text-xs text-slate-400 w-full">
                    <span>{min}</span>
                    <span>{max}</span>
                </div>
            )}

            {(description || error) && !isVertical && (
                <div className="mt-2 text-xs">
                    {description && !error && <p className="text-slate-500">{description}</p>}
                    {error && <p className="text-red-500">{error}</p>}
                </div>
            )}
        </div>
    );
};
