
import { ConditionGroup, ConditionLine } from '../types';

export function applyMask(value: string, mask: string): string {
    if (!mask) return value;

    let result = '';
    let valIdx = 0;
    const cleanValue = value.replace(/[^a-zA-Z0-9]/g, ''); // Start with alphanumeric only

    for (let i = 0; i < mask.length && valIdx < cleanValue.length; i++) {
        const m = mask[i];
        const v = cleanValue[valIdx];

        if (m === '#') {
            if (/\d/.test(v)) {
                result += v;
                valIdx++;
            } else {
                // If expected digit but got letter, we stop or skip?
                // For simplicity, let's stop filling this slot.
                break;
            }
        } else if (m === 'A') {
            if (/[a-zA-Z]/.test(v)) {
                result += v;
                valIdx++;
            } else {
                break;
            }
        } else if (m === '*') {
            result += v;
            valIdx++;
        } else {
            // It's a separator (. , - / etc)
            result += m;
            // If the current value char matches the separator, skip it in cleanValue
            // (this helps when pasting masked values)
            if (v === m) {
                valIdx++;
            }
        }
    }

    return result;
}

export function evaluateConditionLine(line: ConditionLine, values: any): boolean {
    const val = values[line.field];

    // Helper to check for equality that handles potential array values (Checkbox Groups, Multiselects)
    // Helper to check for equality that handles potential array values (Checkbox Groups, Multiselects)
    const isEqual = (a: any, b: any) => {
        // Source value (a) from form values
        // Target value (b) from condition configuration

        if (Array.isArray(b)) {
            // If condition contains multiple target values (Multi-select in builder)
            if (Array.isArray(a)) {
                // Check if any element in form array matches any element in condition array
                return a.some(v => b.some(target => String(v) === String(target)));
            }
            // Check if single form value matches any element in condition array
            return b.some(target => String(a) === String(target));
        }

        const target = String(b);
        if (Array.isArray(a)) {
            // Check if any element in the form array matches the single target string
            return a.some(v => String(v) === target);
        }
        // Handle empty/undefined/null cases consistently
        if (a === undefined || a === null) return target === '' || target === 'undefined' || target === 'null';
        return String(a) === target;
    };

    switch (line.operator) {
        case 'empty':
            return val === undefined || val === null || val === '' || (Array.isArray(val) && val.length === 0);
        case 'not_empty':
            return val !== undefined && val !== null && val !== '' && !(Array.isArray(val) && val.length === 0);
        case 'equal':
        case 'any_equal':
            return isEqual(val, line.value);
        case 'not_equal':
        case 'not_any_equal':
            return !isEqual(val, line.value);
        case 'gt': return Number(val) > Number(line.value);
        case 'gte': return Number(val) >= Number(line.value);
        case 'lt': return Number(val) < Number(line.value);
        case 'lte': return Number(val) <= Number(line.value);
        case 'contains': return String(val).includes(String(line.value));
        default: return true;
    }
}

export function evaluateConditionGroup(group: ConditionGroup, values: any, depth: number = 0): boolean {
    if (depth > 10) return true; // Safety limit
    if (!group || !group.conditions || group.conditions.length === 0) return true;

    const results = group.conditions.map(c => {
        if ('type' in c) return evaluateConditionGroup(c as ConditionGroup, values, depth + 1);
        return evaluateConditionLine(c as ConditionLine, values);
    });

    if (group.type === 'and') {
        return results.every(r => r === true);
    } else {
        return results.some(r => r === true);
    }
}

// Tailwind literal maps to ensure JIT compiler picks them up
const MOBILE_SPANS: Record<number, string> = {
    1: 'col-span-1', 2: 'col-span-2', 3: 'col-span-3', 4: 'col-span-4',
    5: 'col-span-5', 6: 'col-span-6', 7: 'col-span-7', 8: 'col-span-8',
    9: 'col-span-9', 10: 'col-span-10', 11: 'col-span-11', 12: 'col-span-12'
};

const TABLET_SPANS: Record<number, string> = {
    1: 'md:col-span-1', 2: 'md:col-span-2', 3: 'md:col-span-3', 4: 'md:col-span-4',
    5: 'md:col-span-5', 6: 'md:col-span-6', 7: 'md:col-span-7', 8: 'md:col-span-8',
    9: 'md:col-span-9', 10: 'md:col-span-10', 11: 'md:col-span-11', 12: 'md:col-span-12'
};

const DESKTOP_SPANS: Record<number, string> = {
    1: 'lg:col-span-1', 2: 'lg:col-span-2', 3: 'lg:col-span-3', 4: 'lg:col-span-4',
    5: 'lg:col-span-5', 6: 'lg:col-span-6', 7: 'lg:col-span-7', 8: 'lg:col-span-8',
    9: 'lg:col-span-9', 10: 'lg:col-span-10', 11: 'lg:col-span-11', 12: 'lg:col-span-12'
};

export function getResponsiveSpanClasses(mobile: number, tablet: number, desktop: number): string {
    return `${MOBILE_SPANS[mobile] || 'col-span-12'} ${TABLET_SPANS[tablet] || 'md:col-span-12'} ${DESKTOP_SPANS[desktop] || 'lg:col-span-12'}`;
}

